class Solution {
    public int findMinimumOperations(String s1, String s2, String s3) {
        int i = s1.length() - 1, j = s2.length() - 1, k = s3.length() - 1, count = 0;
        while (i >= 0 && j >= 0 && k >= 0) {
            if (s1.charAt(i) == s2.charAt(j) && s2.charAt(j) == s3.charAt(k)) {
                i--;
                j--;
                k--;
            } else {
                count++;
                if (s1.charAt(i) != s2.charAt(j) && s1.charAt(i) != s3.charAt(k) && s2.charAt(j) != s3.charAt(k)) {
                    return -1;
                } else if (s1.charAt(i) != s2.charAt(j) && s1.charAt(i) != s3.charAt(k)) {
                    if (s2.charAt(j) == s3.charAt(k)) {
                        i--;
                    } else if (s1.charAt(i) == s3.charAt(k)) {
                        j--;
                    } else {
                        k--;
                    }
                } else if (s2.charAt(j) != s3.charAt(k) && s1.charAt(i) == s2.charAt(j)) {
                    k--;
                } else if (s1.charAt(i) == s3.charAt(k) && s2.charAt(j) != s3.charAt(k)) {
                    j--;
                } else {
                    i--;
                }
            }
        }
        return i + j + k + count;
    }
}
